import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def travel_time(pos1, pos2):
        return np.linalg.norm(pos1 - pos2) / truck_speed

    def temporal_fitness(start_time, end_time, arrival_time):
        # Calculate how urgent it is to visit this customer
        if arrival_time < start_time:
            return start_time - arrival_time
        elif arrival_time > end_time:
            return arrival_time - end_time
        else:
            return 0

    best_node = None
    lowest_fitness = float('inf')

    for index, customer_pos in enumerate(unvisited_customers):
        travel = travel_time(cur_truck_pos, customer_pos)
        arrival_time = current_time + travel
        start_window, end_window = time_windows[index]

        # Calculate fitness: consider both travel time and adherence to the time window
        fitness = travel + temporal_fitness(start_window, end_window, arrival_time)

        if fitness < lowest_fitness:
            lowest_fitness = fitness
            best_node = index

    return best_node
